defmodule Lists do
  def max_of(l), do: Enum.max(l)
end

defmodule Pairs do
  def swap({a, b}), do: {b, a}
end

defmodule Acc do
  @doc "Sums 1..n."
  @spec sum_to(non_neg_integer) :: non_neg_integer
  def sum_to(0), do: 0
  def sum_to(n), do: n + sum_to(n - 1)
end

defmodule Stack do
  def push(stack, value), do: [value | stack]
  def pop([h | t]), do: {h, t}
  def size(stack), do: length(stack)
end
